  const survivors = livingCells.filter(([x, y]) => {
    const neighbors = countLiveNeighbors(x, y);
    return neighbors === 2 || neighbors === 3;
  });

  const deadCandidates = new Set<string>();
  for (const [x, y] of livingCells) {
    for (const [dx, dy] of neighborOffsets) {
      const nx = x + dx;
      const ny = y + dy;
      if (!isAlive(nx, ny)) {
        deadCandidates.add(`${nx},${ny}`);
      }
    }
  }

  const births: Cell[] = [];
  for (const key of deadCandidates) {
    const [x, y] = key.split(",").map(Number) as [number, number];
    if (countLiveNeighbors(x, y) === 3) {
      births.push([x, y]);
    }
  }

  return [...survivors, ...births];
}
